targets.expr:
vmware_vm_datastore_totalReadLatency_average{vcenter=~"$vcenter"}
* on(vm) group_left()
(
  count by(vm) (
    vmware_vm_datastore_capacity_used{vcenter=~"$vcenter", dsmo=~"$dsmo"}
    * on(vm) group_left()
    vmware_vm_info{vcenter=~"$vcenter", hostmo=~"$hostmo"}
  ) > 0
)

vmware_vm_datastore_totalWriteLatency_average{vcenter=~"$vcenter"}
* on(vm) group_left()
(
  count by(vm) (
    vmware_vm_datastore_capacity_used{vcenter=~"$vcenter", dsmo=~"$dsmo"}
    * on(vm) group_left()
    vmware_vm_info{vcenter=~"$vcenter", hostmo=~"$hostmo"}
  ) > 0
) * -1

vmware_vm_datastore_read_average{vcenter=~"$vcenter"}
* on(vm) group_left()
(
  count by(vm) (
