    * on(vm) group_left()
    vmware_vm_info{vcenter=~"$vcenter", hostmo=~"$hostmo"}
  ) > 0
)

vmware_vm_datastore_write_average{vcenter=~"$vcenter"}
* on(vm) group_left()
(
