    * on(vm) group_left()
    vmware_vm_info{vcenter=~"$vcenter", hostmo=~"$hostmo"}
  ) > 0
) * -1

vmware_vm_datastore_numberReadAveraged_average{vcenter=~"$vcenter"}
* on(vm) group_left()
(
  count by(vm) (
    vmware_vm_datastore_capacity_used{vcenter=~"$vcenter", dsmo=~"$dsmo"}
    * on(vm) group_left()
    vmware_vm_info{vcenter=~"$vcenter", hostmo=~"$hostmo"}
  ) > 0
)

vmware_vm_datastore_numberWriteAveraged_average{vcenter=~"$vcenter"}
* on(vm) group_left()
(
  count by(vm) (
    vmware_vm_datastore_capacity_used{vcenter=~"$vcenter", dsmo=~"$dsmo"}
    * on(vm) group_left()
    vmware_vm_info{vcenter=~"$vcenter", hostmo=~"$hostmo"}
